@Entity
@Inheritance(strategy = InheritanceType.SINGLE_TABLE)
@DiscriminatorColumn(name = "payment_type")
public abstract class Payment { @Id private Long id; private double amount; }

@Entity
@DiscriminatorValue("CC")
public class CreditCardPayment extends Payment { private String cardNumber; }

@Entity
@DiscriminatorValue("PAYPAL")
public class PayPalPayment extends Payment { private String email; }

